Rules.InvariantScript:
If(
    locDeletedWindowMeasure,
    Select(gal_Measure_Select,2,btn_Measure_Select__Status);
    UpdateContext({locDeletedWindowMeasure: false});
);
ClearCollect(
    colNotCompletedWindows,
    Filter(
        colCdsWindowMeasurements,
        'Job Entry'.'Job Entry'=gblRecordJobEntryCurrent_.'Job Entry',
        !Completed,
        Type = gblOptionSets.WindowMeasurement.Type.Tech,
        Status <> gblOptionSets.WindowMeasurement.Status.Inactive
    )
);
// clear variables
UpdateContext(
    {
        locShowMeasurement: ""
    }
);
//reset screen
Reset(gal_Measure_WidthWhole);
Reset(gal_Measure_WidthFraction);
Reset(gal_Measure_HeightWhole);
Reset(gal_Measure_HeightFraction);

UpdateContext(
    {
        locBlockUserInput: false,
        locBlockTimerStart: false,
        locClickedWindowActionsMenu: false,
        locDeletedWindowMeasure: false,
        locShowMeasurement: "",
        locShowWindowActionsMenu: false
    }
);
Reset(tog_Measure_Exception);

// assign tech measurement name
With(
    {
        varType: "colCdsWindowMeasurements",
        varRecordRef: gblRecordWindowMeasurement_Tech.'Window Measurement'
    }, 

    Patch(
        colCdsWindowMeasurements,
        LookUp(colCdsWindowMeasurements, 'Window Measurement' = varRecordRef),
        {
            'Exception?': If(
                tog_Measure_Exception.Value,
                gblOptionSets.WindowMeasurement.Exception.Yes,
                gblOptionSets.WindowMeasurement.Exception.No
            ),
            Name: Left(
                Concatenate(
                    "Tech ",
                    If(btn_Measure_Width.Text="Tap to select", "0" , btn_Measure_Width.Text),
                    " x ",
                    If(btn_Measure_Height.Text="Tap to select", "0" , btn_Measure_Height.Text)
                ),
                50
            ),
            Width: gblMeasurementWidthWhole + gblMeasurementWidthFraction,
            Height: gblMeasurementHeightWhole + gblMeasurementHeightFraction,
            'United Inches (UI)': RoundUp(
                    gblMeasurementWidthWhole + gblMeasurementWidthFraction + gblMeasurementHeightWhole + gblMeasurementHeightFraction,
                    0
            )
        }
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    );
    // update project side menu
    Patch(
        colProjectSidebar,
        gblProjectSidebarItemCurrent,
        {
            Description: "Tech Measurement",
            Title: $"{btn_Measure_Width.Text} x {btn_Measure_Height.Text}"
        }
    );
    Set(
        gblProjectSidebarItemCurrent,
        LookUp(
            colProjectSidebar,
            ID=gblProjectSidebarItemCurrent.ID
        )
    );
);


// save local data

IfError( // This line of code is added to hide the errors

If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
)

,Blank()) // This line of code is added to hide the errors
;
Navigate('Measurements Screen');

With(
    {
        varType: "colCdsWindowMeasurements",
        varRecordRef: GUID()
    },
    // create new sales measurement
    Set(
        gblRecordWindowMeasurement_Tech,
        Patch(
            colCdsWindowMeasurements,
            Defaults(colCdsWindowMeasurements),
            {
                Name: "Tech 0"" x 0""",
                'Exception?': gblOptionSets.WindowMeasurement.Exception.No,
                Height: 0,
                Job: gblRecordJobCurrent,
                'Job Entry': gblRecordJobEntryCurrent_,
                Type: gblOptionSets.WindowMeasurement.Type.Tech,
                Width: 0,
                'Window Measurement': varRecordRef
            }
        )
    );
    Collect(
        colAUDRecords,
        {
            Type: varType,
            RecordRef: varRecordRef,
            Job: gblRecordJobCurrent.Job,
            Operation: "A"
        }
    );
    // set sales measurement to blank
    Set(
        gblRecordWindowMeasurement_Sales,
        Blank()
    )
);
// add window measurement to project sidebar
Collect(
    colProjectSidebar,
    {
        ID: gblRecordWindowMeasurement_Tech.'Window Measurement',
        Title: $"{RoundDown(gblRecordWindowMeasurement_Tech.Width, 0)} {Switch(
            Mod(gblRecordWindowMeasurement_Tech.Width, 1),
            0, "",
            0.125, "1/8",
            0.250, "1/4",
            0.375, "3/8",
            0.500, "1/2",
            0.625, "5/8",
            0.750, "3/4",
            0.875, "7/8"
        )}"" x {RoundDown(gblRecordWindowMeasurement_Tech.Height, 0)} {Switch(
            Mod(gblRecordWindowMeasurement_Tech.Height, 1),
            0, "",
            0.125, "1/8",
            0.250, "1/4",
            0.375, "3/8",
            0.500, "1/2",
            0.625, "5/8",
            0.750, "3/4",
            0.875, "7/8"
        )}""",
        Category: "Window Measurement",
        Description: "Tech Measurement",
        Image: gblAppIcons.Ruler,
        ImageDisabled: gblAppIcons.RulerDisabled,
        Screen: 'Measure Window Screen'
    }
);
Set(
    gblProjectSidebarItemCurrent,
    Last(colProjectSidebar)
);
// determine measurement ranges
Clear(colMeasureWidth);
Clear(colMeasureHeight);
Clear(colMeasureJambDepth);
Clear(colMeasureMaxProjection);
Clear(colMeasureSoffitDepth);
Clear(colMeasureWallThickness);
With(
    {
        varWidthMin: Value(gblRecordWindowChoice.'Min Width'),
        varWidthRange: Value(gblRecordWindowChoice.'Max Width') - Value(gblRecordWindowChoice.'Min Width'),
        varHeightMin: Value(gblRecordWindowChoice.'Min Height'),
        varHeightRange: Value(gblRecordWindowChoice.'Max Height') - Value(gblRecordWindowChoice.'Min Height'),
        varJambDepthMin: Value(gblRecordWindowChoice.'Min Jamb Depth'),
        varJambDepthRange: Value(gblRecordWindowChoice.'Max Jamb Depth') - Value(gblRecordWindowChoice.'Min Jamb Depth'),
        varMaxProjectionMin: Value(gblRecordWindowChoice.'Min Max Projection'),
        varMaxProjectionRange: Value(gblRecordWindowChoice.'Max Max Projection') - Value(gblRecordWindowChoice.'Min Max Projection'),
        varSoffitDepthMin: Value(gblRecordWindowChoice.'Min Soffit Depth'),
        varSoffitDepthRange: Value(gblRecordWindowChoice.'Max Soffit Depth') - Value(gblRecordWindowChoice.'Min Soffit Depth'),
        varWallThicknessMin: Value(gblRecordWindowChoice.'Min Wall Thickness'),
        varWallThicknessRange: Value(gblRecordWindowChoice.'Max Wall Thickness') - Value(gblRecordWindowChoice.'Min Wall Thickness')
    },
    Concurrent(
        ForAll(
            Sequence(varWidthRange+1),
            Collect(
                colMeasureWidth,
                {tblValue: ThisRecord.Value + varWidthMin - 1}
            )
        ),
        ForAll(
            Sequence(varHeightRange+1),
            Collect(
                colMeasureHeight,
                {tblValue: ThisRecord.Value + varHeightMin - 1}
            )
        ),
        ForAll(
            Sequence(varJambDepthRange+1),
            Collect(
                colMeasureJambDepth,
                {tblValue: ThisRecord.Value + varJambDepthMin - 1}
            )
        ),
        ForAll(
            Sequence(varMaxProjectionRange+1),
            Collect(
                colMeasureMaxProjection,
                {tblValue: ThisRecord.Value + varMaxProjectionMin - 1}
            )
        ),
        ForAll(
            Sequence(varSoffitDepthRange+1),
            Collect(
                colMeasureSoffitDepth,
                {tblValue: ThisRecord.Value + varSoffitDepthMin - 1}
            )
        ),
        ForAll(
            Sequence(varWallThicknessRange+1),
            Collect(
                colMeasureWallThickness,
                {tblValue: ThisRecord.Value + varWallThicknessMin - 1}
            )
        )
    )

);
Concurrent(
    Set(
        gblMeasurementWidthWhole,
        RoundDown(
            If(
                gblRecordWindowMeasurement_Tech.Width = 0,
                gblRecordWindowMeasurement_Sales.Width,
                gblRecordWindowMeasurement_Tech.Width
            ),
            0
        )
    ),
    Set(
        gblMeasurementHeightWhole,
        RoundDown(
            If(
                gblRecordWindowMeasurement_Tech.Height = 0,
                gblRecordWindowMeasurement_Sales.Height,
                gblRecordWindowMeasurement_Tech.Height
            ),
            0
        )
    ),
    Set(
        gblMeasurementJambDepthWhole,
        RoundDown(
            gblRecordWindowMeasurement_Tech.'Jamb Depth',
            0
        )
    ),
    Set(
        gblMeasurementMaxProjectionWhole,
        RoundDown(
            gblRecordWindowMeasurement_Tech.'Max Projection',
            0
        )
    ),
    Set(
        gblMeasurementSoffitDepthWhole,
        RoundDown(
            gblRecordWindowMeasurement_Tech.'Soffit Depth',
            0
        )
    ),
    Set(
        gblMeasurementWallThicknessWhole,
        RoundDown(
            gblRecordWindowMeasurement_Tech.'Wall Thickness',
            0
        )
    ),
    Set(
        gblMeasurementWidthFraction,
        With(
            {
                varWidth: If(
                    gblRecordWindowMeasurement_Tech.Width = 0,
                    gblRecordWindowMeasurement_Sales.Width,
                    gblRecordWindowMeasurement_Tech.Width
                )
            },
            varWidth - RoundDown(
                varWidth,
                0
            )
        )
    ),
    Set(
        gblMeasurementHeightFraction,
        With(
            {
                varHeight: If(
                    gblRecordWindowMeasurement_Tech.Height = 0,
                    gblRecordWindowMeasurement_Sales.Height,
                    gblRecordWindowMeasurement_Tech.Height
                )
            },
            varHeight - RoundDown(
                varHeight,
                0
            )
        )
    ),
    Set(
        gblMeasurementJambDepthFraction,
        gblRecordWindowMeasurement_Tech.'Jamb Depth' - RoundDown(
            gblRecordWindowMeasurement_Tech.'Jamb Depth',
            0
        )
    ),
    Set(
        gblMeasurementMaxProjectionFraction,
        gblRecordWindowMeasurement_Tech.'Max Projection' - RoundDown(
            gblRecordWindowMeasurement_Tech.'Max Projection',
            0
        )
    ),
    Set(
        gblMeasurementSoffitDepthFraction,
        gblRecordWindowMeasurement_Tech.'Soffit Depth' - RoundDown(
            gblRecordWindowMeasurement_Tech.'Soffit Depth',
            0
        )
    ),
    Set(
        gblMeasurementWallThicknessFraction,
        gblRecordWindowMeasurement_Tech.'Wall Thickness' - RoundDown(
            gblRecordWindowMeasurement_Tech.'Wall Thickness',
            0
        )
    )
);
Set(
    gblMeasurementMaxUI,
    gblRecordWindowChoice.'Max UI'
);
// reset screen
Reset(gal_Windows_Select);
// next screen
Navigate(
    'Measure Window Screen',
    ScreenTransition.None,
    {locShowWindowActionsMenu: locShowWindowActionsMenu}
);
// update not completed windows
ClearCollect(
    colNotCompletedWindows,
    Filter(
        colCdsWindowMeasurements,
        'Job Entry'.'Job Entry'=gblRecordJobEntryCurrent_.'Job Entry',
        !Completed,
        Type = gblOptionSets.WindowMeasurement.Type.Tech,
        Status <> gblOptionSets.WindowMeasurement.Status.Inactive
    )
);

LookUp(colProjectSidebar, ID=gblProjectSidebarItemCurrent.ID)
/*
IfError(
    Index(
        colProjectSidebar,
        3
    ),
    Blank()
)
*/
//LookUp(colProjectSidebar, ID=gblRecordWindowMeasurement_Tech.'Window Measurement')

If(
    And(
        locClickedWindowActionsMenu,
        locShowWindowActionsMenu,
        gblProjectSidebarItemCurrent.ID = ThisItem.ID
    ),
    UpdateContext({locShowWindowActionsMenu: false}),
    And(
        locClickedWindowActionsMenu,
        !locShowWindowActionsMenu//,
        //gblProjectSidebarItemCurrent.ID = ThisItem.ID
    ),
    UpdateContext({locShowWindowActionsMenu: true})
);
UpdateContext({locClickedWindowActionsMenu: false});
Set(
    gblProjectSidebarItemCurrent,
    ThisItem
);
If(
    And(
        ThisItem.Category = "Job Entry",
        !(App.ActiveScreen.Name="Windows Screen")
    ),
    Navigate(
        'Windows Screen',
        ScreenTransition.None,
        {locShowWindowActionsMenu: locShowWindowActionsMenu}
    ),
    ThisItem.Category = "Window Measurement",
    Set(
        gblRecordWindowMeasurement_Tech,
        LookUp(
            colCdsWindowMeasurements,
            'Window Measurement' = ThisItem.ID
        )
    );
    // check if Job Completed status
If(
        gblRecordJobCurrent.Completed = gblOptionSets.Job.CompletedJob.No,
        Set(
            gblRecordWindowChoice,
            LookUp(
                colCdsWindowChoices,
                'Window Choice' = gblRecordJobEntryCurrent_.'Window Choice'.'Window Choice'
            )
        );
        Set(
            gblRecordWindowMeasurement_Sales,
            LookUp(
                colCdsWindowMeasurements,
                'Window Measurement' = gblRecordJobEntryCurrent_.'Measurement (Sales)'.'Window Measurement'
            )
        );
        Clear(colMeasureWidth);
        Clear(colMeasureHeight);
        Clear(colMeasureJambDepth);
        Clear(colMeasureMaxProjection);
        Clear(colMeasureSoffitDepth);
        Clear(colMeasureWallThickness);
        With(
            {
                varWidthMin: Value(gblRecordWindowChoice.'Min Width'),
                varWidthRange: Value(gblRecordWindowChoice.'Max Width') - Value(gblRecordWindowChoice.'Min Width'),
                varHeightMin: Value(gblRecordWindowChoice.'Min Height'),
                varHeightRange: Value(gblRecordWindowChoice.'Max Height') - Value(gblRecordWindowChoice.'Min Height'),
                varJambDepthMin: Value(gblRecordWindowChoice.'Min Jamb Depth'),
                varJambDepthRange: Value(gblRecordWindowChoice.'Max Jamb Depth') - Value(gblRecordWindowChoice.'Min Jamb Depth'),
                varMaxProjectionMin: Value(gblRecordWindowChoice.'Min Max Projection'),
                varMaxProjectionRange: Value(gblRecordWindowChoice.'Max Max Projection') - Value(gblRecordWindowChoice.'Min Max Projection'),
                varSoffitDepthMin: Value(gblRecordWindowChoice.'Min Soffit Depth'),
                varSoffitDepthRange: Value(gblRecordWindowChoice.'Max Soffit Depth') - Value(gblRecordWindowChoice.'Min Soffit Depth'),
                varWallThicknessMin: Value(gblRecordWindowChoice.'Min Wall Thickness'),
                varWallThicknessRange: Value(gblRecordWindowChoice.'Max Wall Thickness') - Value(gblRecordWindowChoice.'Min Wall Thickness')
            },
            Concurrent(
                ForAll(
                    Sequence(varWidthRange + 1),
                    Collect(
                        colMeasureWidth,
                        {tblValue: ThisRecord.Value + varWidthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varHeightRange + 1),
                    Collect(
                        colMeasureHeight,
                        {tblValue: ThisRecord.Value + varHeightMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varJambDepthRange + 1),
                    Collect(
                        colMeasureJambDepth,
                        {tblValue: ThisRecord.Value + varJambDepthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varMaxProjectionRange + 1),
                    Collect(
                        colMeasureMaxProjection,
                        {tblValue: ThisRecord.Value + varMaxProjectionMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varSoffitDepthRange + 1),
                    Collect(
                        colMeasureSoffitDepth,
                        {tblValue: ThisRecord.Value + varSoffitDepthMin - 1}
                    )
                ),
                ForAll(
                    Sequence(varWallThicknessRange + 1),
                    Collect(
                        colMeasureWallThickness,
                        {tblValue: ThisRecord.Value + varWallThicknessMin - 1}
                    )
                )
            )
        );
        Concurrent(
            Set(
                gblMeasurementWidthWhole,
                RoundDown(
                    If(
                        gblRecordWindowMeasurement_Tech.Width = 0,
                        gblRecordWindowMeasurement_Sales.Width,
                        gblRecordWindowMeasurement_Tech.Width
                    ),
                    0
                )
            ),
            Set(
                gblMeasurementHeightWhole,
                RoundDown(
                    If(
                        gblRecordWindowMeasurement_Tech.Height = 0,
                        gblRecordWindowMeasurement_Sales.Height,
                        gblRecordWindowMeasurement_Tech.Height
                    ),
                    0
                )
            ),
            Set(
                gblMeasurementJambDepthWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Jamb Depth',
                    0
                )
            ),
            Set(
                gblMeasurementMaxProjectionWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Max Projection',
                    0
                )
            ),
            Set(
                gblMeasurementSoffitDepthWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Soffit Depth',
                    0
                )
            ),
            Set(
                gblMeasurementWallThicknessWhole,
                RoundDown(
                    gblRecordWindowMeasurement_Tech.'Wall Thickness',
                    0
                )
            ),
            Set(
                gblMeasurementWidthFraction,
                With(
                    {
                        varWidth: If(
                            gblRecordWindowMeasurement_Tech.Width = 0,
                            gblRecordWindowMeasurement_Sales.Width,
                            gblRecordWindowMeasurement_Tech.Width
                        )
                    },
                    varWidth - RoundDown(
                        varWidth,
                        0
                    )
                )
            ),
            Set(
                gblMeasurementHeightFraction,
                With(
                    {
                        varHeight: If(
                            gblRecordWindowMeasurement_Tech.Height = 0,
                            gblRecordWindowMeasurement_Sales.Height,
                            gblRecordWindowMeasurement_Tech.Height
                        )
                    },
                    varHeight - RoundDown(
                        varHeight,
                        0
                    )
                )
            ),
            Set(
                gblMeasurementJambDepthFraction,
                gblRecordWindowMeasurement_Tech.'Jamb Depth' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Jamb Depth',
                    0
                )
            ),
            Set(
                gblMeasurementMaxProjectionFraction,
                gblRecordWindowMeasurement_Tech.'Max Projection' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Max Projection',
                    0
                )
            ),
            Set(
                gblMeasurementSoffitDepthFraction,
                gblRecordWindowMeasurement_Tech.'Soffit Depth' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Soffit Depth',
                    0
                )
            ),
            Set(
                gblMeasurementWallThicknessFraction,
                gblRecordWindowMeasurement_Tech.'Wall Thickness' - RoundDown(
                    gblRecordWindowMeasurement_Tech.'Wall Thickness',
                    0
                )
            )
        );
        Set(
            gblMeasurementMaxUI,
            gblRecordWindowChoice.'Max UI'
        );
    );
    // reset screen
    Reset(gal_Windows_Select);
    Reset(tog_Measure_Exception);
    // next screen
    If(
        !Or(
            App.ActiveScreen.Name="Measure Window Screen",
            App.ActiveScreen.Name="Measurements Screen"
        ),
        If(
            gblRecordJobCurrent.Completed = gblOptionSets.Job.CompletedJob.No,
            Navigate(
                'Measure Window Screen',
                ScreenTransition.None,
                {locShowWindowActionsMenu: locShowWindowActionsMenu}
            );
            Navigate(
                'Measurements Screen',
                ScreenTransition.None
            );
        )
    )
)

With(
    {
        varRecordWindowMeasurement: If(
            ThisItem.Category="Window Measurement",
            LookUp(
                colCdsWindowMeasurements,
                'Window Measurement'=ThisItem.ID
            ),
            Blank()
        )
    },
    Or(
        !IsBlank(varRecordWindowMeasurement.'Window Mull'.'Sequence Number'),
        !IsBlank(varRecordWindowMeasurement.'Lead Test: Exterior Result')
    )
)

If(
    gblMeasurementMaxUI < Sum(
        gblMeasurementWidthWhole,
        gblMeasurementWidthFraction,
        gblMeasurementHeightWhole,
        gblMeasurementHeightFraction
    ),
    Set(
        gblMeasurementWidthWhole,
        gblRecordWindowMeasurement_Sales.Width
    );
    Set(
        gblMeasurementWidthFraction,
        0
    );
    Set(
        gblMeasurementHeightWhole,
        gblRecordWindowMeasurement_Sales.Height
    );
    Set(
        gblMeasurementHeightFraction,
        0
    )
)

With(
    {
        varType: "colCdsWindowMeasurements",
        varRecordRef: gblRecordWindowMeasurement_Tech.'Window Measurement'
    },
    Patch(
        colCdsWindowMeasurements,
        LookUp(
            colCdsWindowMeasurements,
            'Window Measurement' = varRecordRef
        ),
        {
            'Exception?': If(
                tog_Measure_Exception.Value,
                gblOptionSets.WindowMeasurement.Exception.Yes,
                gblOptionSets.WindowMeasurement.Exception.No
            )
        }
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    );

);
// save local data
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
);

// block user input
UpdateContext({locBlockTimerStart: true});
UpdateContext({locBlockUserInput: true});
// update measurement
Switch(
    locShowMeasurement,
    "Width",
    Set(
        gblMeasurementWidthWhole,
        ThisItem.tblValue
    );
    Patch(
        colCdsWindowMeasurements,
        LookUp(colCdsWindowMeasurements, 'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement'),
        {
            Name: Left(
                Concatenate(
                    "Tech ",
                    If(btn_Measure_Width.Text="Tap to select", "0""" , btn_Measure_Width.Text),
                    " x ",
                    If(btn_Measure_Height.Text="Tap to select", "0""" , btn_Measure_Height.Text)
                ),
                50
            ),
            Width: gblMeasurementWidthWhole + gblMeasurementWidthFraction,
            'United Inches (UI)': RoundUp(
                    gblMeasurementWidthWhole + gblMeasurementWidthFraction + gblMeasurementHeightWhole + gblMeasurementHeightFraction,
                    0
            )
        }
    ),
    "Jamb Depth",
    Set(
        gblMeasurementJambDepthWhole,
        ThisItem.tblValue
    );
    Patch(
        colCdsWindowMeasurements,
        LookUp(colCdsWindowMeasurements, 'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement'),
        {
            'Jamb Depth': gblMeasurementJambDepthWhole + gblMeasurementJambDepthFraction
        }
    ),
    "Soffit Depth",
    Set(
        gblMeasurementSoffitDepthWhole,
        ThisItem.tblValue
    );
    Patch(
        colCdsWindowMeasurements,
        LookUp(colCdsWindowMeasurements, 'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement'),
        {
            'Soffit Depth': gblMeasurementSoffitDepthWhole + gblMeasurementSoffitDepthFraction
        }
    )
);
With(
    {
        varType: "colCdsWindowMeasurements",
        varRecordRef: gblRecordWindowMeasurement_Tech.'Window Measurement'
    },
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
        colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local data
IfError( //This line of code is added to hide the errors

If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    )
) 
, Blank()) //This line of code is added to hide the errors
; 
// reset controls
Reset(gal_Measure_WidthWhole);
// block user input
UpdateContext({locBlockUserInput: false, locShowMeasurement: "", locBlockTimerStart: false});

// block user input
UpdateContext({locBlockTimerStart: true});
UpdateContext({locBlockUserInput: true});
// update measurement
Switch(
    locShowMeasurement,
    "Width",
    Set(
        gblMeasurementWidthFraction,
        ThisItem.valIncrement
    );
    Patch(
        colCdsWindowMeasurements,
        LookUp(colCdsWindowMeasurements, 'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement'),
        {
            Name: Left(
                Concatenate(
                    "Tech ",
                    If(btn_Measure_Width.Text="Tap to select", "0" , btn_Measure_Width.Text),
                    " x ",
                    If(btn_Measure_Height.Text="Tap to select", "0" , btn_Measure_Height.Text)
                    ),
                50
            ),
            Width: gblMeasurementWidthWhole + gblMeasurementWidthFraction,
            'United Inches (UI)': RoundUp(
                    gblMeasurementWidthWhole + gblMeasurementWidthFraction + gblMeasurementHeightWhole + gblMeasurementHeightFraction,
                    0
            )
        }
    ),
    "Jamb Depth",
    Set(
        gblMeasurementJambDepthFraction,
        ThisItem.valIncrement
    );
    Patch(
        colCdsWindowMeasurements,
        LookUp(
            colCdsWindowMeasurements,
            'Window Measurement' = gblRecordWindowMeasurement_Tech.'Window Measurement'
        ),
        {'Jamb Depth': gblMeasurementJambDepthWhole + gblMeasurementJambDepthFraction}
    ),
    "Soffit Depth",
    Set(
        gblMeasurementSoffitDepthFraction,
        ThisItem.valIncrement
    );
